import java.io.*;

public class FileClassExample {
    public static void main(String[] args) {
        // Creating File objects
        File file = new File("test.txt");
        File directory = new File("myfolder");

        // 1. File metadata
        System.out.println("=== File Metadata ===");
        try {
            if (file.exists()) {
                System.out.println("Name: " + file.getName());
                System.out.println("Absolute path: " + file.getAbsolutePath());
                System.out.println("Parent: " + file.getParent());
                System.out.println("Size: " + file.length() + " bytes");
                System.out.println("Last modified: " + file.lastModified());
                System.out.println("Can read: " + file.canRead());
                System.out.println("Can write: " + file.canWrite());
                System.out.println("Is file: " + file.isFile());
                System.out.println("Is directory: " + file.isDirectory());
            } else {
                System.out.println("File doesn't exist!");
            }
        } catch (Exception e) {
            System.out.println("Error: " + e.getMessage());
        }

        // 2. Creating files and directories
        System.out.println("=== Creating ===");
        try {
            // Create a directory
            if (!directory.exists()) {
                boolean created = directory.mkdir();
                System.out.println("Directory created: " + created);
            }

            // Create a file
            File newFile = new File("myfolder/newfile.txt");
            if (!newFile.exists()) {
                boolean created = newFile.createNewFile();
                System.out.println("File created: " + created);
            }
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }

        // 3. Listing directory contents
        System.out.println("=== Listing Directory ===");
        File currentDir = new File(".");  // Current directory
        String[] files = currentDir.list();
        if (files != null) {
            System.out.println("Files in current directory:");
            for (String name : files) {
                File f = new File(name);
                if (f.isDirectory()) {
                    System.out.println("📁 " + name + "/");
                } else {
                    System.out.println("📄 " + name + " (" + f.length() + " bytes)");
                }
            }
        }

        // 4. File operations: rename and delete
        System.out.println("=== Operations ===");
        try {
            // Rename file
            File oldFile = new File("myfolder/newfile.txt");
            File newFile2 = new File("myfolder/renamed.txt");
            if (oldFile.exists()) {
                boolean renamed = oldFile.renameTo(newFile2);
                System.out.println("File renamed: " + renamed);
            }

            // Delete file
            File toDelete = new File("myfolder/renamed.txt");
            if (toDelete.exists()) {
                boolean deleted = toDelete.delete();
                System.out.println("File deleted: " + deleted);
            }

            // Delete directory (must be empty)
            File dirToDelete = new File("myfolder");
            if (dirToDelete.exists() && dirToDelete.isDirectory()) {
                String[] contents = dirToDelete.list();
                if (contents == null || contents.length == 0) {
                    boolean deleted = dirToDelete.delete();
                    System.out.println("Directory deleted: " + deleted);
                } else {
                    System.out.println("Directory not empty, can't delete!");
                }
            }
        } catch (SecurityException e) {
            System.out.println("Security error: " + e.getMessage());
        }

        // 5. Path operations
        System.out.println("=== Path Operations ===");
        File path = new File("parent" + File.separator + "child" + File.separator + "file.txt");
        System.out.println("Path: " + path.getPath());
        System.out.println("File separator: " + File.separator);
        System.out.println("Path separator: " + File.pathSeparator);
    }
}

phase2.brokenCode:
import java.io.*;

public class Test {
    public static void main(String[] args) {
        File file = new File("test.txt");

        // Trying to delete a file that's open
        try (FileWriter fw = new FileWriter(file)) {
            fw.write("Hello");
            // File is still open
        }

        // Delete while file might still be open
        boolean deleted = file.delete();
        System.out.println("Deleted: " + deleted);
    }
}

phase2.explanation:
delete() returns false when it can't delete the file. In this case, the file might still be open or locked.

Even though try-with-resources closes the file, the OS might have a lock on it.

FIX: Check return value and handle failure:
if (file.delete()) {
    System.out.println("File deleted!");
} else {
    System.out.println("Failed to delete file!");
}

Or use Files.delete() which throws exception on failure:
Files.delete(file.toPath());  // Throws IOException on failure

Always check return values of file operations!

